mapper.select:
SELECT id, service_name, job_code, job_name, job_type, cron_expr, next_run_time, run_mode, enabled, timeout_ms, remark, params_json, create_by, create_time, update_by, update_time FROM job_def
deleted = 0
AND service_name = #{dto.serviceName}
AND job_code LIKE CONCAT('%', #{dto.jobCode}, '%')
AND job_name LIKE CONCAT('%', #{dto.jobName}, '%')
AND job_type = #{dto.jobType}
AND enabled = #{dto.enabled}
AND create_time >= #{dto.createTimeStart}
AND create_time <= #{dto.createTimeEnd}
ORDER BY create_time DESC, id DESC

mapper.update:
UPDATE job_def
SET next_run_time = #{nextRunTime}
WHERE id = #{id}
  AND deleted = 0
